const body = $input.first().json.body || $input.first().json;
const notas = body.notas || '';
if (!notas) throw new Error('Campo notas obrigatório');
return [{ json: { notas } }];

const raw = $input.first().json.text || $input.first().json.output || '';
const clean = raw.replace(/```json|```/g, '').trim();
try {
  const parsed = JSON.parse(clean);
  return [{ json: { status: 'ok', dados: parsed } }];
} catch {
  return [{ json: { status: 'erro', mensagem: 'Não foi possível processar as notas.' } }];
}
